import Foundation

class AnalyticsDebugger {
    static let shared = AnalyticsDebugger()

    private init() {}

    func logUserInteraction(_ interaction: String) {
        NSLog("User Interaction: \(interaction)")
    }

    func logAuthenticationFlow(_ step: String, userID: String?) {
        if let userID = userID {
            NSLog("Auth Flow Step: \(step), UserID: \(userID)")
        } else {
            NSLog("Auth Flow Step: \(step), No User ID")
        }
    }

    func logAPICall(url: URL, method: HTTPMethod, requestPayload: Any?, responsePayload: Any?, error: Error?) {
        let methodString = "\(method.rawValue)"
        let urlString = "\(url)"
        let requestPayloadString = (requestPayload != nil) ? String(describing: requestPayload!) : "nil"
        let responsePayloadString = (responsePayload != nil) ? String(describing: responsePayload!) : "nil"
        let errorString = (error != nil) ? error?.localizedDescription ?? "nil" : "nil"

        NSLog("API Call - URL: \(urlString), Method: \(methodString), Request Payload: \(requestPayloadString), Response Payload: \(responsePayloadString), Error: \(errorString)")
    }

    func logUserDataChange(_ changeType: String, userID: String?, emailAddress: String?) {
        let userInfo = (userID != nil) ? "UserID: \(userID!)" : ""
        let emailInfo = (emailAddress != nil) ? ", Email: \(emailAddress!)" : ""

        NSLog("User Data Change - Type: \(changeType), \(userInfo)\(emailInfo)")
    }

    func logError(_ error: Error, context: String?) {
        let errorDescription = error.localizedDescription
        let contextString = (context != nil) ? " in Context: \(context!)" : ""

